function getLatest(uint256 lengthSlot) internal view returns (uint256) {
    uint256 length = checkpoints[lengthSlot].length;
    if (length == 0) return 0;
    uint256 checkpointSlot = lengthSlot + length - 1;
    return checkpoints[checkpointSlot].value;
}

